- 'top 3 readings' refers to the readings with the highest values; 
- 'active sensors' refers to sensors with a status of 'active'; 
- 'good quality readings' refers to readings with a quality flag of 'good'.

sql:
SELECT AVG(eod_value) AS average_eod_value, MAX(max_value) AS max_daily_value
FROM daily_summaries
WHERE thedate = '2015-06-22';

SELECT sensor_type_name, COUNT(DISTINCT unit_of_measurement) AS distinct_units
FROM sensor_types
GROUP BY sensor_type_name;

SELECT COUNT(*) 
FROM trend_smoothing
WHERE window_size = 10;
